38	      const policyStep = scenario.steps[step.policy] as QuoteStep;
39	      const policyTypes = new Set(policyStep.items.map((item) => item.type));
40	      const damageCounts = new Map<string, number>();
41	      for (const damage of step.incident.damages) {
42	        if (!policyTypes.has(damage.itemType)) {
43	          return errorResult(`claim damage itemType ${damage.itemType} not in policy`);
44	        }
45	        if (damage.amount < 0) {
46	          return errorResult(`claim damage amount must be non-negative: ${damage.amount}`);
47	        }
48	        damageCounts.set(damage.itemType, (damageCounts.get(damage.itemType) ?? 0) + 1);
49	      }
